INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-318395', 'Animal Company', ARRAY['adventure','action'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/coauu2.jpg', 'Enter the chaotic and fun world of Animal Company, where survival meets pure chaos in this multiplayer VR adventure. Whether you’re exploring eerie environments, customizing your character in the Lab, or braving the terrors that await you and your friends, the excitement never stops. With weekly updates, there’s always something fresh to experience.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1026', 'The Legend of Zelda: A Link to the Past', ARRAY['puzzle','adventure','action'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co3vzn.jpg', 'Venture back to Hyrule and an age of magic and heroes. The predecessors of Link and Zelda face monsters on the march when a menacing magician takes over the kingdom. Only you can prevent his evil plot from shattering the land of Hyrule.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1103', 'Super Metroid', ARRAY['action','platformer','adventure','metroidvania'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co5osy.jpg', 'The Space Pirates, merciless agents of the evil Mother Brain, have stolen the last Metroid from a research station, and once again Mother Brain threatens the safety of the galaxy! Samus Aran must don her awesome array of high-tech weaponry to retrieve the deadly Metroid hidden deep within the cave-riddled planet Zebes. Super Metroid features excellent graphics, with a huge variety of enemies and worlds to explore. The side-view action will be familiar to many players, only now there are new weap', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1070', 'Super Mario World', ARRAY['platformer','adventure','action'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co8lo8.jpg', 'A 2D platformer and first entry on the SNES in the Super Mario franchise, Super Mario World follows Mario as he attempts to defeat Bowser''s underlings and rescue Princess Peach from his clutches. The game features a save system, a less linear world map, an expanded movement arsenal and numerous new items for Mario, alongside new approaches to level design and art direction.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1454', 'Suikoden II', ARRAY['rpg','strategy','turn-based'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co1y6a.jpg', 'Experience An Epic Tale of Warfare, Magic, Friendship And Betrayal
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-119133', 'Elden Ring', ARRAY['rpg','adventure','action','open-world'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co4jni.jpg', 'Elden Ring is an action RPG developed by FromSoftware and published by Bandai Namco Entertainment, released in February 2022. Directed by Hidetaka Miyazaki, with world-building contributions from novelist George R. R. Martin, the game features an expansive open world called the Lands Between. Players assume the role of a customisable character known as the Tarnished, who must explore this world, battle formidable enemies, and seek to restore the Elden Ring to become the Elden Lord.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-119171', 'Baldur''s Gate III', ARRAY['rpg','strategy','turn-based','action'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co670h.jpg', 'An ancient evil has returned to Baldur''s Gate, intent on devouring it from the inside out. The fate of Faerun lies in your hands. Alone, you may resist. But together, you can overcome.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-7346', 'The Legend of Zelda: Breath of the Wild', ARRAY['puzzle','adventure','action','sandbox','open-world'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co3p2d.jpg', 'The Legend of Zelda: Breath of the Wild is the first 3D open-world game in the Zelda series. Link can travel anywhere and be equipped with weapons and armor found throughout the world to grant him various bonuses. Unlike many games in the series, Breath of the Wild does not impose a specific order in which quests or dungeons must be completed. While the game still has environmental obstacles such as weather effects, inhospitable lands, or powerful enemies, many of them can be overcome using the ', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-426', 'Final Fantasy III', ARRAY['rpg','adventure','sandbox','open-world'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/coaq5k.jpg', 'Final Fantasy III is the sixth main installment in the Final Fantasy series, developed and published by Square. It was the final title in the series to feature two-dimensional graphics, and the first story that did not revolve around crystals.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1627', 'Super Smash Bros. Melee', ARRAY['action','challenging','platformer'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co21yv.jpg', 'Super Smash Bros. Melee is the second installment in the Super Smash Bros. series and the follow-up to the Nintendo 64 title. It includes all playable characters from the first game, and also adds characters from franchises such as Fire Emblem, of which no games had been released outside Japan at the time. Super Smash Bros. Melee builds on the first game by adding new gameplay features and playable characters: it''s major focus is the multiplayer mode, while still offering a number of single-play', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-119388', 'The Legend of Zelda: Tears of the Kingdom', ARRAY['puzzle','adventure','action','sandbox','open-world'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co5vmg.jpg', 'An epic adventure across the land and skies of Hyrule awaits in The Legend of Zelda: Tears of the Kingdom for Nintendo Switch. The adventure is yours to create in a world fueled by your imagination.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-19560', 'God of War', ARRAY['rpg','action','adventure'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/cobkt6.jpg', 'God of War is the sequel to God of War III as well as a continuation of the canon God of War chronology. Unlike previous installments, this game focuses on Norse mythology and follows an older and more seasoned Kratos and his son Atreus in the years since the third game. It is in this harsh, unforgiving world that he must fight to survive… and teach his son to do the same.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-228530', 'Death Stranding 2: On the Beach', ARRAY['action','adventure','open-world'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co9ipx.jpg', 'Embark on an inspiring mission of human connection beyond the UCA. Sam — with companions by his side — sets out on a new journey to save humanity from extinction. Join them as they traverse a world beset by otherworldly enemies, obstacles and a haunting question: should we have connected?', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1073', 'Super Mario World 2: Yoshi''s Island', ARRAY['platformer','action'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co2kn9.jpg', 'Super Mario World 2: Yoshi''s Island is a platform video game acting as a prequel to 1990''s Super Mario World. The game casts players as Yoshi as he escorts Baby Mario through 48 levels in order to reunite him with his brother Luigi, who had been kidnapped by Baby Bowser''s minions. As a Super Mario series platformer, Yoshi runs and jumps to reach the end of the level while solving puzzles and collecting items. In a style new to the series, the game has a hand-drawn aesthetic and is the first to h', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1077', 'Super Mario Galaxy', ARRAY['platformer','adventure','action'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co21ro.jpg', 'A 3D platformer and first Wii entry in the Super Mario franchise, Super Mario Galaxy sees Mario jump across planets and galaxies with varying items, enemies, geographies and gravity mechanics in order to reach his enemy Bowser, who has attacked the Mushroom Kingdom and hijacked Princess Peach''s castle with her inside.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1105', 'Metroid Prime', ARRAY['action','platformer','adventure','open-world','metroidvania'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co3w4w.jpg', 'A 3D exploration-focused metroidvania with first-person shooting mechanics and the first 3D entry in the Metroid series, Metroid Prime follows Samus Aran after the events of Metroid (1986) as she boards a Space Pirate frigate, then chases her escaping archrival Ridley into the intricately structured Tallon IV, a planet full of deadly wildlife and former home to the advanced and ancient Chozo race.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-25076', 'Red Dead Redemption 2', ARRAY['action','rpg','adventure','open-world'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co1q1f.jpg', 'Red Dead Redemption 2 is the epic tale of outlaw Arthur Morgan and the infamous Van der Linde gang, on the run across America at the dawn of the modern age.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-74', 'Mass Effect 2', ARRAY['action','rpg','adventure'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co20ac.jpg', 'Are you prepared to lose everything to save the galaxy? You''ll need to be, Commander Shephard. It''s time to bring together your greatest allies and recruit the galaxy''s fighting elite to continue the resistance against the invading Reapers. So steel yourself, because this is an astronomical mission where sacrifices must be made. You''ll face tougher choices and new, deadlier enemies. Arm yourself and prepare for an unforgettable intergalactic adventure.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-9927', 'Persona 5', ARRAY['rpg','adventure'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co1r76.jpg', 'Persona 5, a turn-based JRPG with visual novel elements, follows a high school student with a criminal record for a crime he didn''t commit. Soon he meets several characters who share similar fates to him, and discovers a metaphysical realm which allows him and his friends to channel their pent-up frustrations into becoming a group of vigilantes reveling in aesthetics and rebellion while fighting corruption.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-126098', 'Half-Life: Alyx', ARRAY['action','puzzle','adventure'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co87vg.jpg', 'Half-Life: Alyx is Valve’s VR return to the Half-Life series. It’s the story of an impossible fight against a vicious alien race known as the Combine, set between the events of Half-Life and Half-Life 2. Alyx Vance and her father Eli mount an early resistance to the Combine''s brutal occupation of Earth.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-26758', 'Super Mario Odyssey', ARRAY['platformer','adventure','action','sandbox','open-world'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co1mxf.jpg', 'Explore incredible places far from the Mushroom Kingdom as you join Mario and his new ally Cappy on a massive, globe-trotting 3D adventure. Use amazing new abilities, like the power to capture and control objects, animals, and enemies to collect Power Moons so you can power up the Odyssey airship and save Princess Peach from Bowser’s wedding plans!', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1942', 'The Witcher 3: Wild Hunt', ARRAY['rpg','adventure','action','open-world'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/coaarl.jpg', 'The Witcher 3: Wild Hunt is an open-world action role-playing game developed by CD Projekt Red.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-303811', 'Astro Bot', ARRAY['platformer','adventure','action'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/coba3k.jpg', 'Buckle up for some epic PlayStation camaraderie, join forces with your favourite PlayStation icons and show the universe that small is mighty in this fresh new Astro adventure, exclusive to PS5 consoles!', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1078', 'Super Mario Galaxy 2', ARRAY['platformer','adventure','action'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co21tl.jpg', 'Super Mario Galaxy 2 is the sequel to Super Mario Galaxy and the fourth 3D platformer entry in the Mario franchise. The sequel retains many elements from its predecessor, such as the adventure being in outer space, the element of gravity, and recurring objects such as Launch Stars and Sling Stars. Returning items include the Bee Mushroom and the Fire Flower. However, the game introduces new elements as well, such as the utilization of Yoshi, new power-ups like the Cloud Flower, and the use of a ', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-3363', 'Mario & Luigi: Bowser''s Inside Story', ARRAY['rpg','adventure','action'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co21vr.jpg', 'Mario & Luigi: Bowser''s Inside Story is the third game in the Mario & Luigi series of games. Players control Mario and Luigi simultaneously in the side-scrolling platform environment of Bowser''s body, while also controlling the Koopa King himself in the top-down world of the Mushroom Kingdom. Similar to games like Earthbound, enemy encounters are seen as actual enemies that players can avoid or attempt to strike early. The actual battles are a combination of turn-based menu attacks, and timed re', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-112875', 'God of War Ragnarök', ARRAY['rpg','action','adventure','open-world'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/coba3d.jpg', 'God of War: Ragnarök is the ninth installment in the God of War series and the sequel to 2018''s God of War. Continuing with the Norse mythology theme, the game is set in ancient Norway and features series protagonists Kratos, the former Greek God of War, and his young son Atreus. The game kicked off the events of Ragnarök, where Kratos and Atreus must journey to each of the Nine Realms in search of answers as they prepare for the prophesied battle that will end the world.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-26192', 'The Last of Us Part II', ARRAY['action','adventure'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co5ziw.jpg', 'The Last of Us Part II is an action-adventure game set five years after the events of The Last of Us. The player traverses post-apocalyptic environments such as buildings and forests to advance the story. They can use firearms, improvised weapons, and stealth to defend against hostile humans and cannibalistic creatures infected by a mutated strain of the Cordyceps fungus. The game intermittently switches control between Ellie and Abby, and also briefly Joel in the opening sequence. The nimble na', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-45181', 'Mass Effect Trilogy', ARRAY['action','rpg','adventure'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co4a7a.jpg', 'Experience all three award winning Mass Effect titles at an amazing value with the Mass Effect Trilogy.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-23', 'System Shock', ARRAY['action','rpg'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co4e44.jpg', 'A seminal cyberpunk first-person exploratory adventure game with RPG elements in which, waking up in the Citadel Space Station, a lone hacker has to survive corrupted enemies and collect audio logs and equipment from former station workers in order to shut down SHODAN, the station''s artificial intelligence that has killed everyone on board and now intends to destroy the world.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-24493', 'Fate/Grand Order', ARRAY['rpg','adventure','visual-novel','action'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co1qq4.jpg', 'Fate/Grand Order is a turn-based role-playing game with some visual novel elements set in the Fate/stay franchise, for iOS and Android.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1009', 'The Last of Us', ARRAY['action','adventure'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co1r7f.jpg', 'The Last of Us is a third-person action-adventure game featuring a mix of exploration, stealth and combat. Players face both infected creatures and hostile human enemies while progressing through varied environments. The game includes a narrative-driven single-player campaign and a competitive online multiplayer mode called Factions. Trophy support is included, and additional downloadable content was made available separately.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1802', 'Chrono Trigger', ARRAY['rpg','open-world'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co3plw.jpg', 'In this turn-based Japanese RPG, young Crono must travel through time through a misfunctioning teleporter to rescue his misfortunate companion and take part in an intricate web of past and present perils. The adventure that ensues soon unveils an evil force set to destroy the world, triggering Crono''s race against time to change the course of history and bring about a brighter future.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1128', 'Castlevania: Symphony of the Night', ARRAY['platformer','rpg','adventure','action','open-world','metroidvania'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co53m8.jpg', 'Having been awoken from his eternal slumber by the reappearance of Castlevania, Alucard must once again face the evil minions of darkness. Use your vampiric powers, along with weapons, potions, and other magical relics to change the tide of battle.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1600', 'Gran Turismo 3: A-Spec', ARRAY['racing','simulation'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co5xru.jpg', 'More than two years in the making, Gran Turismo 3 A-spec features over 150 detailed cars -- each composed of more than 4,000 polygons -- 60 beginner, amateur and professional championship races, as well as ten endurance races and ten rally races. In addition to all-new special effects, such as sun glare, heat distortion and reflections, Gran Turismo 3 A-spec also offers up a soundtrack of more than 20 licensed tracks, and an even better replay mode with TV-style camera views. Two players can go ', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-338106', 'Donkey Kong Bananza', ARRAY['platformer','adventure','action'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/cobd1q.jpg', 'Donkey Kong Bananza is exclusively on Nintendo Switch 2! Explore a vast underground world—by smashing your way through it! Bash, throw, and climb through just about anything in DK’s brand-new 3D platforming action-adventure game!', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-272', 'Unreal Tournament', ARRAY['action'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co2k3b.jpg', 'Unreal Tournament is a first-person arena shooter video game developed by Epic Games and Digital Extremes. It was the second installment in the Unreal series.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1691', 'Advance Wars', ARRAY['simulation','strategy','turn-based','action'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/cob9nu.jpg', 'Just because this battle fits in the palm of your hand doesn''t mean the stakes are small. On the contrary, this all-or-nothing fight will have you accessing guns, grenades, launchers, and weaponry of all sorts. Players assume command of an army that''s out to reclaim a world that''s been broken up by warring factions. The battle map is essentially a grid, and moving units is like moving chess pieces on a board -- each of the units can move a specific amount of spaces within this grid, and can only', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-565', 'Uncharted 2: Among Thieves', ARRAY['action','platformer','adventure'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co1tnb.jpg', 'In the sequel to Drake''s Fortune, Nathan Drake comes across a map that showcases the location of Marco Polo''s missing ships. It takes him on a journey to find the infamous Cintamani Stone, and uncover the truth behind it.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-68', 'Master of Orion II: Battle at Antares', ARRAY['strategy','turn-based','4x'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co2fhi.jpg', 'Master of Orion 2 also known as MOO2 is considered the classic 4x turn based strategy game set in space. The game has a kind of cult status and even by to days standards is still only matched in game play by very few of its competitors.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-298526', 'Kingdom Come: Deliverance II', ARRAY['rpg','simulation','adventure','action','open-world'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co8qmv.jpg', 'A thrilling story-driven action RPG, with a rich open world, set in 15th century Medieval Europe. Experience the ultimate medieval adventure - through the eyes of young Henry - as you embark on a journey of epic proportions.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-116', 'Star Wars: Knights of the Old Republic', ARRAY['rpg','adventure','action','open-world'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co1tmz.jpg', 'Choose Your Path! Set 4,000 years before the Galactic Empire, you are the last hope for the Jedi Order and the Republic - can you master the ways of the Force to become their savior? Or will you fall to the dark side and achieve ultimate power? Hero, villain, peacekeeper, or chaos-bringer... you and your party will determine the fate of the galaxy!
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-7331', 'Uncharted 4: A Thief''s End', ARRAY['action','adventure'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co1r7h.jpg', 'Several years after his last adventure, retired fortune hunter, Nathan Drake, is forced back into the world of thieves. With the stakes much more personal, Drake embarks on a globe-trotting journey in pursuit of a historical conspiracy behind a fabled pirate treasure. His greatest adventure will test his physical limits, his resolve, and ultimately what he''s willing to sacrifice to save the ones he loves.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-2765', 'SpongeBob SquarePants: Battle For Bikini Bottom', ARRAY['platformer','adventure','action'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co3iyp.jpg', 'The evil Plankton has set in motion his most diabolical plot ever! The fate of Bikini Bottom has been put into the unsuspecting hands of SpongeBob. Explore a huge world filled with unexpected surprises, challenges, and familiar friends. Join SpongeBob and his friends in his fearless crusade to end Plankton''s evil scheme...', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-72', 'Portal 2', ARRAY['platformer','puzzle','adventure','action'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co1rs4.jpg', 'Sequel to the acclaimed Portal (2007), Portal 2 pits the protagonist of the original game, Chell, and her new robot friend, Wheatley, against more puzzles conceived by GLaDOS, an A.I. with the sole purpose of testing the Portal Gun''s mechanics and taking revenge on Chell for the events of Portal. As a result of several interactions and revelations, Chell once again pushes to escape Aperture Science Labs.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1029', 'The Legend of Zelda: Ocarina of Time', ARRAY['puzzle','adventure','action','sandbox','open-world'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co3nnx.jpg', 'The Legend of Zelda: Ocarina of Time is the fifth main installment of The Legend of Zelda series and the first to be released for the Nintendo 64. It was one of the most highly anticipated games of its age, and is listed among the greatest video games ever created by numerous websites and magazines. The gameplay of Ocarina of Time was revolutionary for its time, it has arguably made more of an impact on later games in the series than any of its predecessors even though they had the same cores of', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-9643', 'Return of the Obra Dinn', ARRAY['puzzle','adventure','indie'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co27j9.jpg', 'In this 1-bit first-person mystery game, a merchant ship called the Obra Dinn has appeared at a London harbor, years after being declared lost at sea. As an insurance adjuster, the player must examine the ship for clues.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-14593', 'Hollow Knight', ARRAY['platformer','adventure','indie','action','metroidvania','atmospheric'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/cobfzp.jpg', 'A 2D metroidvania with an emphasis on close combat and exploration in which the player enters the once-prosperous now-bleak insect kingdom of Hallownest, travels through its various districts, meets friendly inhabitants, fights hostile ones and uncovers the kingdom''s history while improving their combat abilities and movement arsenal by fighting bosses and accessing out-of-the-way areas.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-732', 'Grand Theft Auto: San Andreas', ARRAY['action','racing','adventure','open-world'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co2lb9.jpg', 'Returning after his mother''s murder to the semi-fictional city of Los Santos (based on Los Angeles), Carl Johnson, a former gang banger, must take back the streets for his family and friends by gaining respect and once again gaining control over the streets. However, a story filled with crime, lies and corruption will lead him to trudge the entire state of San Andreas (based on California and Nevada) to rebuild his life.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-196770', 'Sunflower Land', ARRAY['simulation','farming'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co521n.jpg', 'Farm, Gather, Cook, Raise Animals, Fish, Craft & Trade your NFTs in this Web3 RPG based farming simulator', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1595', 'Star Citizen', ARRAY['action','rpg','simulation','adventure','indie','sandbox','open-world'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/coauzg.jpg', 'Star Citizen is a sandbox open-world MMO "SpaceSim" by Cloud Imperium Games. Explore the ''verse, fight, trade, and more when you play Star Citizen!', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-136482', 'Undertale Yellow', ARRAY['rpg','strategy','turn-based','adventure','indie'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co2el1.jpg', 'Welcome to Undertale Yellow. In this fan made prequel to the RPG Undertale, you control a human who falls underground into the world of monsters... but will you make it out alive?
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-143761', 'Pokémon Infinite Fusion', ARRAY['rpg','adventure','indie','action'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co7k5u.jpg', 'Pokémon Infinite Fusion is a fangame RPG based on the Pokémon fusion generator trend, featuring sprite art from many different artists.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-224415', 'Voices of the Void', ARRAY['simulation','indie','sandbox','open-world','atmospheric'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co8uks.jpg', 'You work as a scientist in the isolated research lab in the mountains of Switzerland. Your task is to gather signals from space, analyze them, process them and sell them to get points.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-117526', 'Lurkers', ARRAY['action','platformer','rpg','simulation','adventure','indie','sandbox','open-world'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co9hgu.jpg', 'Lurkers is a chaotic 2D multiplayer sandbox where you can build, battle, and survive! Fight zombies, conquer game modes like Bedwars, and unleash your creativity in a world that’s yours to shape and destroy.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1046', 'Star Control II', ARRAY['simulation','strategy','adventure','indie','action'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co2d9l.jpg', 'Star Control II, the sequel to the original Star Control, is a space adventure game that features role-playing elements alongside a 2D space ship melee combat system. The player assumes the role of The Captain of a single starship wandering a detailed environment of solar systems, gradually gathering information and resources in order to defeat a mysterious and implacable enemy.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-305296', 'Hunter Moonstrike', ARRAY['action','rpg','adventure','indie','open-world'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co96tr.jpg', 'Hunter Moonstrike is the first survival game integrated with artificial intelligence. In this game, all npc have their own unique story and you can see the story of the game from their point of view. Talk to any person, ask any question you like, they will answer and think they are alive', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-178264', 'Bad End Theater', ARRAY['puzzle','simulation','adventure','indie','visual-novel'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co44y4.jpg', 'Welcome to Bad End Theater! Select your protagonist and explore a variety of terrible fates! The decisions you make in one story will affect the others. you can toggle these behaviors to open up new paths! unfortunately, every path leads to a bad ending... Can you find a way to save this unlucky cast? Playtime: 2-3 hours to see all endings (it''s a puzzle game, so this varies widely).', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-98753', 'My Grandfather''s Farm', ARRAY['rpg','simulation','strategy','adventure','indie','farming'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/s9v8ggxiaqwtp3n0koas.jpg', '"Your grandfather left you his old farm. With only a few coins and tools and with the help of your grandfather you have to go to the old farm 
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-84197', 'Faith', ARRAY['adventure','indie'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co48pe.jpg', 'Faith is a pixel horror game inspired by the era of MS-DOS, Apple II, Atari, and ZX Spectrum classics.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-139403', 'Jungles of Maxtheria', ARRAY['platformer','adventure','indie','action'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co2i39.jpg', 'Play as either "Hot Spot" Harvey, his cousin Roxy Roks, Junior or Missy searching for the lost treasure of the infamous "Jaxton Max". Your quest for fortune and glory will not be easy however. This adventure is full of baddies aimed at stopping you dead in your tracks. Use knives to dig through walls, bullets to battle the baddies, grappling hooks to jump over long distances, oxygen tanks to breath under water and torches to see what lurks underground. Collect keys to get past locked doors and t', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-140133', 'Enigma of Fear', ARRAY['puzzle','adventure','indie','action'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co93ft.jpg', 'Become Mia, a paranormal detective searching for her missing father inside the Perimeter - a place that doesn''t exist. Investigate clues like a real detective and unravel the mysteries behind the Enigma of Fear, defeating the terrible monsters who''ll try to stop you.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-145439', 'Escape Simulator', ARRAY['puzzle','simulation','adventure','indie'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co49cc.jpg', 'Escape Simulator is a next-gen escape room experience: pick up and examine everything, move furniture, smash pots and melt locks! Play solo or with a friend to solve cryptic puzzles and riddles.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-135478', 'Hrot', ARRAY['action','indie'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co2omv.jpg', 'Hrot is a single-player retro FPS set in a small socialist country neighboring Soviet Union (Czechoslovakia) after an unspecified disaster in 1986. Those times were dark and terrifying and so is the game.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-119801', 'Figment 2: Creed Valley', ARRAY['puzzle','adventure','indie','action','atmospheric'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co3m7p.jpg', 'Figment 2: Creed Valley is an encore to Figment. Dusty and Piper have restored peace in The Mind, however, a new adversary is threatening its balance. Our two heroes must travel to Creed Valley, where The Mind’s beliefs and ideals are formed, to face their most menacing and theatrical foe so far.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-113112', 'Hades', ARRAY['rpg','action','adventure','indie','roguelike'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/cob9kr.jpg', 'A rogue-lite hack and slash dungeon crawler in which Zagreus, son of Hades the Greek god of the dead, attempts to escape his home and his oppressive father by fighting the souls of the dead through the various layers of the ever-shifting underworld, while getting to know and forging relationships with its inhabitants.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-228525', 'Hades II', ARRAY['rpg','action','adventure','indie','roguelike'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/coaknx.jpg', 'Battle beyond the Underworld using dark sorcery to take on the Titan of Time in this bewitching sequel to the award-winning rogue-like dungeon crawler.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-12517', 'Undertale', ARRAY['puzzle','rpg','strategy','turn-based','adventure','indie'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/cob1t2.jpg', 'A small child falls into the Underground, where monsters have long been banished by humans and are hunting every human that they find. The player controls the child as they try to make it back to the Surface through hostile environments, all the while engaging with a turn-based combat system with puzzle-solving and bullet hell elements, as well as other unconventional game mechanics.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-26472', 'Disco Elysium', ARRAY['rpg','adventure','indie'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co1sfj.jpg', 'Disco Elysium is a role-playing game developed and published by ZA/UM. It is set in the fictional city of Revachol, where players assume the role of an amnesiac detective investigating a murder case. The game emphasises dialogue and skill-based choices, with character attributes represented by internal voices that influence decisions and interactions. Its narrative explores themes of politics, philosophy, and personal identity, and it is known for its unconventional gameplay and deep storytellin', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-115289', 'Hollow Knight: Silksong', ARRAY['platformer','adventure','indie','action','metroidvania','atmospheric'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/cobebu.jpg', 'Hollow Knight: Silksong is the epic sequel to Hollow Knight, the epic action-adventure of bugs and heroes. As the lethal hunter Hornet, journey to all-new lands, discover new powers, battle vast hordes of bugs and beasts and uncover ancient secrets tied to your nature and your past.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-120710', 'The Henry Stickmin Collection', ARRAY['adventure','indie','action'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co2mgv.jpg', 'The Henry Stickmin Collection is a Newgrounds choose-your-own-path classic, reborn and revitalized. This 6-game epic culminates in multiple entirely canon, extremely different endings. Each step of the journey has you choose from options such as a Teleporter or calling in your buddy Charles to help you out. Correct choices will move the story forward, but incorrect choices lead to a fail. If you get to the end on your first try, you''re doing it wrong. Failing is half the fun.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-27907', 'Rhythm Doctor', ARRAY['adventure','indie','action'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co9xi0.jpg', 'Save patients with your rhythm mastery! Rhythm Doctor is a rhythm game where you heal patients by defibrillating in time to their heartbeats. Learn each patient''s unique heartbeat and defeat boss viruses trying to sabotage your rhythm, all set to heart-pumping, soul-soothing music.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-28160', 'Atom RPG', ARRAY['rpg','strategy','adventure','indie'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co1qvc.jpg', 'Atom RPG is a post-apocalyptic indie game, inspired by classic CRPGs: Fallout, Wasteland, System Shock, Deus Ex, Baldur''s Gate and many others.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-256090', 'Blood on the Clocktower', ARRAY['rpg','strategy','indie','card-game'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co6q6z.jpg', 'Blood on the Clocktower is a game of murder and mystery, lies and logic, deduction and deception for five-to-twenty courageous players and one devious storyteller.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-318575', 'Epiko Regal', ARRAY['strategy','card-game','action'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co8wq0.jpg', 'Epiko Regal is an immersive mobile strategy game that seamlessly blends collectible card gameplay with tower defense battles. Players build and upgrade their decks, which include a wide range of troops, spells, weapons, and buildings, all deployed strategically onto the battlefield. The objective is to defend your towers and engage in dynamic battles against other players to emerge victorious.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-253735', 'My Racing Career', ARRAY['racing','simulation','strategy'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co9o2e.jpg', 'Start your engines and make your career as a world-class racing driver in one of the most established motorsport management games.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-18870', 'Championship Manager 4', ARRAY['simulation','sport','strategy'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co94ly.jpg', 'Championship Manager 4 series is a football-management simulation computer game.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-178283', 'NFUT Cards', ARRAY['simulation','sport','strategy','card-game'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co45d4.jpg', 'A play to earn football manager video game where the main assets are football collectibles in the form of NFT''s, developed in the Binance Smart Chain.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-37138', 'Sengoku Rance', ARRAY['rpg','strategy','turn-based','adventure','visual-novel','social'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co7k0m.jpg', 'Sengoku Rance (also known as "Rance 7") is the tenth release of the Rance series launched by Alicesoft. The story takes place during the 4th sengoku (warring states) era of JAPAN, an area of the Rance World which parodies medieval real-world Japan.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-8240', 'SOCOM II: U.S. Navy SEALs', ARRAY['action','simulation','strategy'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co99jv.jpg', 'SOCOM II is a third-person tactical shooter. There are 12 different single-player missions: split equally between Albania, Algeria, Brazil and Russia. There are five different ranks that can be played in the game: Ensign, Lieutenant, Commander, Captain and Admiral. The player starts with the first three ranks unlocked, but must finish the single player game on Commander to unlock Captain, and on Captain to unlock Admiral. Players can unlock new models for multiplayer, as well as movies, music, c', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-4268', 'Panzer General', ARRAY['strategy'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co5pbv.jpg', 'You are the brightest and best of the new Axis generals in the Second World War. Your tactical skills will be tested in armored assaults, amphibious invasions, paradrops, naval engagements, and fierce aerial combat for control of the skies. Go from triumph to triumph, invading and seizing the capitals of Great Britain, the Soviet Union, and ultimately the United States of America on your way to conquering the whole world! Can you achieve a place in history?', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-38387', 'Super Bomberman 5', ARRAY['puzzle','strategy','action'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co2w8i.jpg', 'An evil Bomber named Emperor Terrorin who has the power of Time itself has freed various criminal Bombers from their prison cells in orbit around Planet Bomber. Setting them up in a warped time and space, Shirobon, Kurobon, and their Louie (Rui) companions must travel through stages and defeat them before going up against Emperor Terrorin himself. Super Bomberman 5, released by Hudson Soft in early 1997, was the final Bomberman game released on the Super Family Computer - the Japanese version of', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-721', 'Freedom Force vs. The 3rd Reich', ARRAY['rpg','strategy'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co28fk.jpg', 'Freedom is threatened yet again and only Minute Man and his heroic Freedom Force can save the day in the follow up to one of the most critically acclaimed games of 2002.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-3568', 'Ogre Battle 64: Person of Lordly Caliber', ARRAY['strategy','rpg','adventure'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co54xx.jpg', '"Ogre Battle 64: Person of Lordly Caliber is a tactical RPG for the Nintendo 64.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-863', 'Sid Meier''s Alpha Centauri', ARRAY['simulation','strategy','turn-based','4x','farming'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co3wp5.jpg', 'Legendary designer Sid Meier presents the next evolution in strategy games, with the most addictive, compelling gameplay yet. Explore the alien planet that is your new home and uncover its myriad mysteries. Discover over 75 extraordinary technologies. Build over 60 base upgrades and large scales secret projects for your empire. Conquer your enemies with a war machine that you design from over 32,000 possible unit types.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-2899', 'EarthBound', ARRAY['rpg','strategy','turn-based','adventure','action'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co6v07.jpg', 'A turn-based JRPG and sequel to then-Japan-only Earthbound Beginnings (1989) in which Ness, a young boy living in a land based on the USA, leaves home to go on an adventure through strange locations, get to know quirky characters and defeat an unknowable alien threat called Giygas while facing up to the realities of growing up and becoming familiar with the real world.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-152765', 'Castlevania Advance Collection', ARRAY['platformer','rpg','adventure','action'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/cob9xj.jpg', 'Castlevania Advance Collection includes three legendary Castlevania games that were first released in the early 2000s: Circle of the Moon, Aria of Sorrow, and Harmony of Dissonance. In addition, this collection also includes Castlevania: Dracula X and some never-before-seen sketches and artwork from the games!
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-77378', 'Super Mario All-Stars + Super Mario World', ARRAY['platformer','action'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co98uf.jpg', 'Put quite simply, this is the amalgamation of the previously released Super Mario All-Stars compilation with Super Mario World added. While games already in the All-Stars bundle have major graphical and audio improvements, the only change made to Super Mario World is a slight tweak of Luigi''s graphic sprites, making him slightly thinner and taller (rather than being the same height and stature of Mario) which does not affect gameplay.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1112', 'Metroid Prime: Trilogy', ARRAY['action','platformer','puzzle','adventure','metroidvania'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co404a.jpg', 'In this compilation that bundles all three landmark Metroid Prime games, experience the danger and high-intense action of facing space alone as you play skilled bounty hunter, Samus Aran.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-275923', 'A Twisted Path To Renown', ARRAY['action','rpg','simulation','sandbox','open-world'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co7d0t.jpg', 'A Twisted Path To Renown: is a Multiplayer, loot-focused, PvEvP extraction shooter, set in the rugged 1899 United States!
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-145327', 'Town Star', ARRAY['simulation','sandbox'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co2wwf.jpg', 'Gala Games'' Town Star, a new game from the creative minds behind Farmville by Zynga, is a masterpiece of town-building, organization and time management.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-8204', 'iRacing', ARRAY['racing','simulation','sport'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co2sjw.jpg', 'From NASCAR, rallycross, and Aussie Supercars to sports cars and Grand Prix racing, iRacing has it all. All you need is a computer, a gaming wheel or game pad that simply plugs into the USB port of your computer and an Internet connection. iRacing centrally organizes all of the racing for you with over 150 cars and tracks, 40 official series , or you can choose to host your own race or race in one of over 800 private leagues.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-21084', 'The Ico & Shadow of the Colossus Collection', ARRAY['simulation','adventure','action','open-world'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co4ako.jpg', 'The Ico & Shadow of the Colossus Collection is a video game bundle that contains high-definition remasters of two older PlayStation 2 games for the PlayStation 3, and was developed by Bluepoint Games and released alongside Ico as The Ico & Shadow of the Colossus Collection in September 2011.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-5563', 'IL-2 Sturmovik: 1946', ARRAY['action','simulation','strategy'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co22aq.jpg', 'Oleg Maddox’s world famous IL-2 Sturmovik series of flight simulators continues to expand. The latest offering, IL-2 1946, adds 36 new planes, four new gigantic maps, over a hundred new ground objects, and nearly 200 new campaign missions. This new opus also includes all of the previous Il-2 series content. What years ago began as a one-aircraft study sim is now an astonishing anthology, with a whopping 229 flyable aircraft and over 300 aircraft total! Not to mention that players will have the o', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-28278', 'Catan Universe', ARRAY['strategy','card-game'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co22ve.jpg', 'After a long, hardship filled journey you have reached the coast of an unknown island! However, other explorers have also landed on Catan: The race for colonisation has begun! Build roads and towns, trade skilfully and become ruler over Catan!', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-42791', 'Yu-Gi-Oh! ARC-V Tag Force Special', ARRAY['strategy','card-game'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co4kot.jpg', 'Yu-Gi-Oh! ARC-V Tag Force Special is the seventh installment of the Tag Force video game series.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
