INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-346148', 'The Salma World', ARRAY['puzzle','strategy','turn-based','card-game'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co9vz2.jpg', 'A gaming site that contains interactive games with chat on Twitch and chilling games, contain wheel , Tetris , countries war, question and answers games and drums of war, and more soon .. Most of them are interactive games with chat on Twitch.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-40477', 'Slay the Spire', ARRAY['rpg','strategy','turn-based','adventure','indie','card-game','roguelike'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co1iyf.jpg', 'We fused card games and roguelikes together to make the best single player deckbuilder we could. Craft a unique deck, encounter bizarre creatures, discover relics of immense power, and Slay the Spire!', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-251833', 'Balatro', ARRAY['strategy','turn-based','indie','card-game','roguelike'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co9f4g.jpg', 'Balatro is a deck-building roguelite in which players construct poker hands to earn chips and overcome enemy blinds. The game features mechanics for enhancing a deck of playing cards, purchasing Jokers that modify hand effects, and discovering synergies to progress through increasingly challenging encounters.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-57153', 'The Battle of Polytopia', ARRAY['simulation','strategy','turn-based','adventure','indie','card-game','action','4x'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/coav77.jpg', 'The Battle of Polytopia is an award-winning turn-based strategy game about building a civilization and going into battle. With millions of players, it has quickly become one of the most popular mobile strategy games.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-121586', 'Wingspan', ARRAY['strategy','indie','card-game'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co1xh8.jpg', 'In Wingspan you are bird enthusiasts - researchers, bird watchers, ornithologists, and collectors - seeking to discover and attract the best birds to your network of wildlife preserves.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-12443', 'Magic: The Gathering', ARRAY['strategy','turn-based','card-game'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co2err.jpg', 'Magic: The Gathering is a computer game published by MicroProse in April 1997 based on the collectible card game Magic: The Gathering.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-425', 'Final Fantasy VIII', ARRAY['rpg','adventure','card-game','open-world'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co2z7d.jpg', 'Final Fantasy VIII is the eighth main installment in the Final Fantasy series. The gameplay makes a departure from many series standards. While it still uses the Active Time Battle system, it deviates from the series'' traditional means of boosting a character''s power via leveling, although levels are not completely abandoned as they were in Final Fantasy II. In addition, it does not have a Magic Point-based system for spell-casting. Instead, magic is collected, drawn, and created from items, and', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-2287', 'Pokémon Y', ARRAY['rpg','strategy','turn-based','adventure','card-game','open-world'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co1z9m.jpg', 'Your adventure in Pokémon X and Pokémon Y takes place in the Kalos region, home to beautiful skies and forests! The Kalos region is full of interesting places to visit and explore!
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-208533', 'Shogun Showdown', ARRAY['rpg','strategy','turn-based','indie','card-game','action','roguelike'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co6oh5.jpg', 'Shogun Showdown is a turn-based combat game with rogue-like and deck-building elements. Position yourself and attack at the right time, upgrade your tiles and combo them to get ready to face the Shogun!', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-112659', 'Batman: Arkham Collection', ARRAY['action','adventure','open-world'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co8wgm.jpg', 'Batman: Arkham Collection includes the definitive versions of Rocksteady''s Arkham Trilogy games, including all post-launch content, in one complete collection.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-240168', 'PlayM2M', ARRAY['rpg','action','adventure'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co9l8q.jpg', 'Unlock the secrets of magic and become a master in the massively multiplayer online role-playing game (MMORPG)! Show your skills to your enemies in epic PVE and take part in brutal Battleground PvP!', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-307930', 'NextWorld2', ARRAY['rpg','action'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co8gqz.jpg', 'NextWorld2 is a fantasy MMORPG set in the divided world of Kigan, where two rival kingdoms, Selakim and Quila, struggle for dominance. Players can choose from four classes: Warrior, Shaman, Assassin, and Ezra, and explore a vast open world filled with quests, mounts, dungeons, and large-scale community events.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-499', 'God of War III', ARRAY['action','adventure'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co3koi.jpg', 'Set in the realm of brutal Greek mythology, God of War III is a single-player game that allows players to take on the climatic role of the ex-Spartan warrior, Kratos, as he scales through the intimidating heights of Mt. Olympus and the dark depths of Hell to seek revenge on those who have betrayed him. Armed with double-chained blades, and an array of new weapons and magic for this iteration of the trilogy, Kratos must take on mythology''s darkest creatures while solving intricate puzzles through', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-75235', 'Ghost of Tsushima', ARRAY['rpg','action','adventure','open-world'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co2crj.jpg', 'Uncover the hidden wonders of Tsushima in this open-world action adventure. Forge a new path and wage an unconventional war for the freedom of Tsushima. Challenge opponents with your katana, master the bow to eliminate distant threats, develop stealth tactics to ambush enemies in order to win over the mongols.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-2135', 'Bayonetta 2', ARRAY['action','adventure'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/cob9e9.jpg', 'The witching hour strikes again. Brimming with intricate battles that take place in, on and all over epic set pieces, Bayonetta 2 finds our sassy heroine battling angels and demons in unearthly beautiful HD. You’re bound to love how it feels to string together combos with unimaginable weapons and to summon demons using Bayonetta’s Umbran Weave in this frantic stylized action game.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-501', 'Batman: Arkham City', ARRAY['action','adventure','open-world','metroidvania'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co1voh.jpg', 'Batman: Arkham City builds upon the intense, atmospheric foundation of Batman: Arkham Asylum, sending players soaring into Arkham City, the new maximum security "home" for all of Gotham City''s thugs, gangsters and insane criminal masterminds.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-551', 'God of War II', ARRAY['platformer','action','adventure'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co3dik.jpg', 'God of War II, an action-adventure hack-and-slash video game, was developed by Santa Monica Studio and published by Sony Computer Entertainment (SCE). Initially launched for the PlayStation 2, it serves as the second installment in the God of War series, the sixth in chronological order, and a sequel to 2005''s God of War. The game is rooted in Greek mythology and unfolds in ancient Greece, revolving around the theme of vengeance. The protagonist, Kratos, is the new God of War, having defeated th', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-126', 'Diablo II', ARRAY['rpg','action','atmospheric'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co3gfq.jpg', 'Like its predecessor, Diablo II is an action role-playing game with dark fantasy and horror themes. The player controls a new hero attempting to stop the destruction unleashed by Diablo''s return. The game''s 4 acts feature a variety of locations and settings to explore and battle in, as well as an increased cast of characters to play as and interact with. Diablo II had become one of the most popular online games of all time. Major factors that contributed to Diablo II''s success include what fans ', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-5623', 'Severance: Blade of Darkness', ARRAY['action','challenging','rpg','adventure'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co7nlj.jpg', 'Severance: Blade of Darkness follows the fate of four characters and their quest to defeat an evil Necromancer and retrieve a legendary sword. The player can choose between the characters, who are a Knight, a Barbarian, A Dwarf and a Ranger/ Amazon type female character. All characters have different starting areas but eventually end up in the same levels. Yet, the sequence of the stages can be chosen as a world map in between the stages prompts you to decide where you want to go next, maybe loo', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-136879', 'Black Myth: Wukong', ARRAY['rpg','action','adventure'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co8h3y.jpg', 'Black Myth: Wukong is an action RPG rooted in Chinese mythology. The story is based on Journey to the West, one of the Four Great Classical Novels of Chinese literature. You shall set out as the Destined One to venture into the challenges and marvels ahead, to uncover the obscured truth beneath the veil of a glorious legend from the past.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-549', 'God of War', ARRAY['puzzle','action','adventure'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co3ddc.jpg', 'God of War is an action-adventure hack-and-slash video game developed by Santa Monica Studio and published by Sony Computer Entertainment (SCE). Initially launched for the PlayStation 2, the game stands as the first instalment in the God of War series and the third in chronological order. Loosely inspired by Greek mythology, it unfolds in ancient Greece with vengeance as its central theme. The player takes on the role of Kratos, the protagonist, a Spartan warrior devoted to the Olympian gods. Ta', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-19565', 'Marvel''s Spider-Man', ARRAY['action','adventure','open-world'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co1r77.jpg', 'Starring the world’s most iconic Super Hero, Spider-Man features the acrobatic abilities, improvisation and web-slinging that the wall-crawler is famous for, while also introducing elements never-before-seen in a Spider-Man game. From traversing with parkour and utilizing the environment, to new combat and blockbuster set pieces, it’s Spider-Man unlike any you’ve played before.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-125642', 'Path of Exile 2', ARRAY['rpg','action','adventure'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co8ae0.jpg', 'Path of Exile 2 is a next generation Action RPG created by Grinding Gear Games. Set years after the original Path of Exile, you will return to the dark world of Wraeclast and seek to end the corruption that is spreading. Path of Exile 2 is a free-to-play online multiplayer game with co-op for up to six players.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-5503', 'Batman: Arkham Knight', ARRAY['action','adventure','open-world'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/coagib.jpg', 'Batman: Arkham Knight is an action-adventure game developed by Rocksteady Studios, released in 2015. It is the final installment in the Arkham series. Players control Batman as he faces Scarecrow, who unites Gotham''s criminals to destroy the Dark Knight. The mysterious Arkham Knight, a new adversary, aids Scarecrow in his plan.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-180876', 'Astral Ascent', ARRAY['platformer','adventure','indie','action','roguelike'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co4o04.jpg', 'Choose one of four heroes and explore the Garden, an astral prison guarded by 12 powerful mystical bosses: the Zodiacs. Challenge them with dozens of unique spells and faithful friends by your side to unfold the story of this platform roguelite with lightning fast combat.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-16983', 'Dungeon Crawl Stone Soup', ARRAY['rpg','strategy','roguelike'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/coaxez.jpg', 'Dungeon Crawl Stone Soup is a roguelike dungeon crawler.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-8145', 'Spelunky Classic', ARRAY['platformer','puzzle','indie','action','roguelike'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co1y65.jpg', 'Spelunky is a cave exploration / treasure-hunting game inspired by classic platform games and roguelikes, where the goal is to grab as much treasure from the cave as possible. Every time you play the cave''s layout will be different. Use your wits, your reflexes, and the items available to you to survive and go ever deeper! Perhaps at the end you may find what you''re looking for...
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-18730', 'Cataclysm: Dark Days Ahead', ARRAY['rpg','simulation','adventure','indie','action','sandbox','open-world','4x','strategy','roguelike'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co2hqe.jpg', 'Cataclysm: Dark Days Ahead (aka Cataclysm DDA or CataDDA) is an open source survival horror roguelike set in a post-apocalyptic and fictional New England.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-208417', 'Ravenswatch', ARRAY['rpg','action','adventure','roguelike'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co8vwy.jpg', 'Fallen heroes of old folk tales and legends: you are on the verge of a crucial battle against the Nightmare invading and corrupting your world. A roguelike action game from the creators of Curse of the Dead Gods, playable solo or in online co-op.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-140204', 'BroodStar', ARRAY['action','adventure','indie','roguelike'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co2jc6.jpg', 'BroodStar is a classic arcade shmup with roguelike elements. Battle your way through hordes of enemy creatures, collecting upgrades and fighting terrifying bosses on a quest to destroy the living planet, the BroodStar.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-149657', 'Blue Prince', ARRAY['puzzle','strategy','adventure','indie','roguelike','atmospheric'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co9mzd.jpg', 'Welcome to Mt. Holly, where every dawn unveils a new mystery. Navigate through shifting corridors and ever-changing chambers in this genre-defying strategy puzzle adventure. But will the unpredictable path you create lead you to the rumored Room 46?', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-199736', 'OTXO', ARRAY['action','challenging','simulation','strategy','indie','roguelike'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co62jl.jpg', 'OTXO is a fast, brutal, violent roguelite, filled with precise but savage gunplay and time-bending slow motion.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-24054', 'Caves of Qud', ARRAY['rpg','simulation','strategy','turn-based','adventure','indie','roguelike'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co7eda.jpg', 'Caves of Qud is a science fantasy roguelike epic steeped in retro-futurism, deep simulation, and swathes of sentient plants. The game weaves a handwritten narrative through rich physical, social, and historical simulations. The result is a hybrid handcrafted & procedurally-generated world where you can do just about anything. Assemble your character from over 70 mutations and defects, and 24 castes and kits - it’s all the character diversity you could want. Explore procedurally-generated regions', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-203722', 'Dave the Diver', ARRAY['rpg','simulation','adventure','action','farming','roguelike'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/coaav7.jpg', 'Dave the Diver is an action-adventure and management simulation game developed by Mintrocket. In the game, players control Dave, who spends his days diving into underwater environments to catch fish and gather resources, and his nights managing a sushi restaurant. The gameplay combines real-time underwater exploration and combat with restaurant management mechanics.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-147519', 'Against the Storm', ARRAY['strategy','simulation','indie','roguelike'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/coaazl.jpg', 'A roguelite city builder set in a fantasy world tormented by the everlasting rain. Settle the unknown wilds to discover and rebuild the ruins of a long-forgotten civilization. Develop technologies that will help your citizens tackle destructive storms and extend the frontier of your civilization.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-314476', 'Lost in Random: The Eternal Die', ARRAY['rpg','adventure','indie','action','roguelike'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co9t4g.jpg', 'Lost in Random: The Eternal Die is an action-packed, rogue-lite adventure in the world of Random. Play as Queen Aleksandra and wield her living die-companion Fortune, as they go all in against the ancient evil that took everything from her.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-9627', 'Gnomoria', ARRAY['simulation','strategy','turn-based','indie','sandbox','roguelike'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co2vcf.jpg', 'Gnomoria is a sandbox village management game where you help lead a small group of gnomes, who have set out on their own, to thrive into a bustling kingdom! Anything you see can be broken down and rebuilt elsewhere. Craft items, build structures, set traps and dig deep underground in search of precious resources to help your gnomes survive the harsh lands. Build your kingdom and stockpile wealth to attract wandering gnomads to your cause, but be wary of also attracting enemies!', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-26855', 'Dead Cells', ARRAY['platformer','adventure','indie','action','roguelike','metroidvania'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co7jfv.jpg', 'Dead Cells is a rogue-lite, metroidvania inspired, action-platformer. You''ll explore a sprawling, ever-changing castle... assuming you’re able to fight your way past its keepers in 2D souls-lite combat. No checkpoints. Kill, die, learn, repeat.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-134584', 'Returnal', ARRAY['action','roguelike','atmospheric'], 45, 'https://images.igdb.com/igdb/image/upload/t_720p/co3wc1.jpg', 'Returnal is a 2021 roguelike third-person shooter video game developed by Housemarque and published by Sony Interactive Entertainment.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-186725', 'Vampire Survivors', ARRAY['rpg','adventure','indie','action','roguelike'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co4bzv.jpg', 'Mow thousands of night creatures and survive until dawn! Vampire Survivors is a gothic horror casual game with rogue-lite elements, where your choices can allow you to quickly snowball against the hundreds of monsters that get thrown at you.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-11417', 'Odallus: The Dark Call', ARRAY['platformer','puzzle','adventure','indie','action','metroidvania'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co21ey.jpg', 'Odallus is a NES inspired exploration game with lots of action. It brings elements of classics such as Ghosts’n Goblins, Demon’s Crest and Castlevania while subverting some modern twists.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-19118', 'Clash at Demonhead', ARRAY['platformer','adventure','action','metroidvania'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co6v2y.jpg', 'Clash at Demonhead is an open-ended platformer. The player takes control of Billy "Big Bang" Blitz, who is capable of running, jumping, and shooting. He is initially armed with a handgun, though various upgrades can be purchased from a shop. He later gains the ability to perform various powers by collecting Force, including shrinking, teleportation to previously-visited areas, flight, healing, and invincibility. The player chooses levels from a world map that consists of over forty routes. Vario', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-7344', 'Ori and the Blind Forest', ARRAY['platformer','puzzle','adventure','action','metroidvania'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co1y41.jpg', 'The forest of Nibel is dying. After a powerful storm sets a series of devastating events in motion, an unlikely hero must journey to find his courage and confront a dark nemesis to save his home. Ori and the Blind Forest tells the tale of a young orphan destined for heroics, through a visually stunning action-platformer crafted by Moon Studios for Xbox One and PC. Featuring hand-painted artwork, meticulously animated character performance, and a fully orchestrated score, Ori and the Blind Forest', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1136', 'Castlevania: Dawn of Sorrow', ARRAY['platformer','rpg','adventure','action','metroidvania'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/cob9z0.jpg', 'Draw the correct magic seal quickly, or your enemies will never die! Fight and explore through one of the largest castles ever seen in the series! Race another player through custom-made castle rooms in versus mode!
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-194821', 'Nine Sols', ARRAY['platformer','action','adventure','indie','metroidvania'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co4l2s.jpg', 'Nine Sols is a lore rich, hand-drawn 2D action-platformer featuring Sekiro-inspired deflection focused combat, immersive storytelling, and unique Taopunk setting. Embark on a journey of Asian fantasy, explore the land once home to an ancient alien race, and follow a vengeful hero’s quest to slay the 9 Sols, formidable rulers of this forsaken realm.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-121295', 'Grime', ARRAY['platformer','rpg','adventure','indie','action','metroidvania','atmospheric'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co3hbp.jpg', 'Explore a surreal world obsessed with proportions and anatomy, in this 2.5D Metroidvania action RPG, where you will find out what you''re made of... and break everything else apart.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1134', 'Castlevania: Aria of Sorrow', ARRAY['platformer','rpg','adventure','action','metroidvania'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/cob947.jpg', 'The year is 2035 and Soma Cruz is about to witness the first solar eclipse of the 21st century when he suddenly blacks out -- only to awaken inside a mysterious castle. As Soma, you must navigate the castle''s labyrinths while confronting perilous monsters at every turn. But beware, you must escape before the evil consumes you!', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-1111', 'Metroid Prime 3: Corruption', ARRAY['action','platformer','adventure','metroidvania'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/cobaun.jpg', 'The trilogy closes as corruption creeps over the universe… and into Samus Aran. Using the Wii Remote and Nunchuk, players control Samus as she partners with other bounty hunters, shoots down enemies, and explores alien worlds in a harrowing mission to stop the mutagenic Phazon from spreading across the galaxy.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-5619', 'Demon''s Souls', ARRAY['rpg','adventure','action','sandbox','open-world','metroidvania','farming'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co27sk.jpg', 'A third-person action RPG with cooperative and competitive multiplayer elements in which the player enters the kingdom of Boletaria as it is being ravaged by a fog that spawns murderous demons. The player has to hunt down the arch demons situated in five disparate areas within the kingdom and partake in punishing combat to reach the Old One, the vengeful being that brought the fog to Boletaria.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-11782', 'Shantae: Risky''s Revenge', ARRAY['platformer','puzzle','adventure','action','metroidvania'], 30, 'https://images.igdb.com/igdb/image/upload/t_720p/co2ra9.jpg', 'The sequel to the critically acclaimed Shantae is here! Fans asked, and WayForward has answered with a powder keg of high-octane, hair-whipping, hip-shaking action available only on the Nintendo DSiWare service. Shantae: Risky''s Revenge sets the bar even higher with thousands of frames of animation, huge multi-sprite bosses and a quest so big it''s bursting at the seams. Guide "half-genie" Shantae through haunted wastelands, burning deserts, enchanted forests, dripping caverns and deadly labyrint', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-89594', 'Monster Sanctuary', ARRAY['platformer','rpg','strategy','turn-based','adventure','indie','action','metroidvania'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co1q3q.jpg', 'A pixel art monster collecting game featuring sideview visuals, metroidvania like exploration and challenging turn based combat.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-165390', 'Blasphemous II', ARRAY['platformer','rpg','action','adventure','indie','metroidvania'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co6ej3.jpg', 'The Penitent One awakens as Blasphemous 2 joins him once again in an endless struggle against The Miracle. Dive into a perilous new world filled with mysteries and secrets to discover, and tear your way through monstrous foes that stand between you and your quest to end the cycle one and for all.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-293', 'Sid Meier''s Civilization IV', ARRAY['simulation','strategy','turn-based','4x','farming'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co1rjp.jpg', 'Sid Meier and Firaxis Games will take this incredibly fun and addictive game to new heights by adding new ways to play and win, new tools to manage and expand your civilization, all-new easy to use mod capabilities and intense multiplayer modes and options', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-148945', 'Please, Touch the Artwork', ARRAY['puzzle','simulation','adventure','indie','action','atmospheric','relaxing'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co4equ.jpg', 'What happens when you DO touch the artwork? Part Zen-puzzle, part narrative-adventure, you''ll unravel the secret world behind iconic abstract paintings through over 160 puzzles. An aesthetic journey to the origins of modern art, set to a soothing jazzy soundtrack.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-3379', 'Harvest Moon 2 GBC', ARRAY['rpg','simulation','sandbox','farming'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co2xl6.jpg', 'The second Harvest Moon game released on the Game Boy Color, Harvest Moon 2 GBC is a farming simulation in which the player assumes the role of either a boy or a girl who is left a farm and given three years to turn its fortunes around.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-3378', 'Harvest Moon 64', ARRAY['rpg','simulation','sandbox','farming'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co2ae7.jpg', 'Retire to the country for a new challenge in Harvest Moon 64. Hard work is rewarded as you struggle to bring prosperity back to a neglected farm. Work the land, pick up odd-jobs, and get to know the neighbors. Harvest Moon 64 has all the charm of the original Super Nintendo classic, plus many new surprises.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-17000', 'Stardew Valley', ARRAY['rpg','simulation','strategy','adventure','indie','sandbox','farming','relaxing'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/coa93h.jpg', 'Stardew Valley is an open-ended country-life RPG! You’ve inherited your grandfather’s old farm plot in Stardew Valley. Armed with hand-me-down tools and a few coins, you set out to begin your new life. Can you learn to live off the land and turn these overgrown fields into a thriving home? It won’t be easy. Ever since Joja Corporation came to town, the old ways of life have all but disappeared. The community center, once the town’s most vibrant hub of activity, now lies in shambles. But the vall', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-3383', 'Harvest Moon: Friends of Mineral Town', ARRAY['rpg','simulation','sandbox','farming'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co25u5.jpg', 'Turn a long-neglected field of rocks and weeds into a successful farm in this rustic role-playing game.', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-440', 'Medieval II: Total War', ARRAY['strategy','simulation','turn-based','farming'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co8xje.jpg', 'Take command of your armies and expand your reign. Conquer, destroy, rebuild and improve the cities of the greatest medieval nations of the Western and Middle Eastern world. Employ diplomacy to manipulate your allies and enemies and direct epic and visceral real time battles with up to 10,000 meticulously detailed troops shedding blood on lush 3D landscapes complete with dynamic weather effects in order to re-write history and rule the world.
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-279425', 'Ropin'' Ranch', ARRAY['simulation','farming'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co7gyw.jpg', 'Welcome to Ropin'' Ranch, the ultimate Free-To-Play online ranch game that invites you to step into the boots of a seasoned rancher. In this expansive world, you''ll take charge of your very own ranch, tame wild horses, and breed horses with real-world genetics. Unlock horses in over 150+ colors and get unique horses every time with markings! Ropin'' Ranch offers an immersive and educational experience, blending the thrill of ranch life with the intricacies of horse genetics, illnesses, and more. R', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-438', 'Rome: Total War', ARRAY['strategy','simulation','turn-based','farming'], 120, 'https://images.igdb.com/igdb/image/upload/t_720p/co1zt9.jpg', 'Set during the rule of the late Roman Republic and the early Roman Empire, Rome: Total War is a real-time tactics and turn-based strategy game that takes place across Europe, North Africa and the Near East. The player assumes control of one of three Roman families with eight other factions playable outside the main campaign. The main goal of the campaign is to become emperor of Rome by conquering fifty provinces with the support of the people before capturing Rome itself although a short campaig', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
INSERT INTO public.games (id, name, genres, estimated_session_length, header_image, description, source) VALUES ('igdb-119304', 'Spiritfarer', ARRAY['platformer','simulation','adventure','indie','action','farming'], 60, 'https://images.igdb.com/igdb/image/upload/t_720p/co2fe7.jpg', 'Spiritfarer is a cozy management game about dying. You play Stella, ferrymaster to the deceased, a Spiritfarer. Build a boat to explore the world, then befriend and care for spirits before finally releasing them into the afterlife. Farm, mine, fish, harvest, cook, and craft your way across mystical seas. Join the adventure as Daffodil the cat, in two-player cooperative play. Spend relaxing quality time with your spirit passengers, create lasting memories, and, ultimately, learn how to say goodby', 'igdb') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, genres = EXCLUDED.genres, estimated_session_length = EXCLUDED.estimated_session_length, header_image = EXCLUDED.header_image, description = EXCLUDED.description;
